import json, os, glob

all_papers = []
decoder = json.JSONDecoder()

for f in glob.glob('paper_search_results/*.jsonl'):
    with open(f) as fh:
        content = fh.read()
    idx = 0
    while idx < len(content):
        while idx < len(content) and content[idx] in ' \t\n\r':
            idx += 1
        if idx >= len(content):
            break
        try:
            obj, end_idx = decoder.raw_decode(content, idx)
            if isinstance(obj, dict) and 'papers' in obj:
                all_papers.extend(obj['papers'])
            idx = end_idx
        except json.JSONDecodeError:
            idx += 1

# Deduplicate by title
seen = {}
for p in all_papers:
    t = p['title'].strip()
    if t not in seen or p.get('relevance',0) > seen[t].get('relevance',0):
        seen[t] = p

papers = list(seen.values())
papers.sort(key=lambda p: (p.get('relevance',0), p.get('citations',0)), reverse=True)

# Print top papers with arxiv IDs where possible
count = 0
for p in papers:
    if p.get('relevance', 0) < 2:
        continue
    count += 1
    if count > 50:
        break
    url = p.get('url', '')
    arxiv_id = ''
    if 'arxiv.org' in url:
        arxiv_id = url.split('/')[-1].replace('.pdf', '')
