import zlib, re

def check_arxiv_id(filepath):
    with open(filepath, 'rb') as f:
        data = f.read()
    pattern = rb'<<[^>]*FlateDecode[^>]*>>[\r\n]*stream[\r\n]*(.*?)[\r\n]*endstream'
    matches = re.findall(pattern, data, re.DOTALL)
    for m in matches:
        try:
            dec = zlib.decompress(m)
            bt_blocks = re.findall(rb'BT(.*?)ET', dec, re.DOTALL)
            for block in bt_blocks:
                parts = re.findall(rb'\(([^)]+)\)\s*Tj', block)
                for p in parts:
                    try:
                        s = p.decode('utf-8', errors='replace')
                        if 'arXiv' in s or 'cs.' in s or 'astro' in s:
