import zlib, re

def extract_all_text(filepath, max_streams=50):
    with open(filepath, 'rb') as f:
        data = f.read()
    pattern = rb'<<[^>]*FlateDecode[^>]*>>[\r\n]*stream[\r\n]*(.*?)[\r\n]*endstream'
    matches = re.findall(pattern, data, re.DOTALL)
    all_text = []
    for m in matches[:max_streams]:
        try:
            dec = zlib.decompress(m)
            bt_blocks = re.findall(rb'BT(.*?)ET', dec, re.DOTALL)
            for block in bt_blocks:
                parts = re.findall(rb'\(([^)]+)\)\s*Tj', block)
                for p in parts:
                    try:
                        s = p.decode('utf-8', errors='replace')
                        if len(s.strip()) > 1:
                            all_text.append(s)
                    except:
                        pass
                # Also try TJ operator
                tj_parts = re.findall(rb'\[([^\]]+)\]\s*TJ', block)
                for tp in tj_parts:
                    sub = re.findall(rb'\(([^)]+)\)', tp)
                    for s in sub:
                        try:
                            decoded = s.decode('utf-8', errors='replace')
                            if len(decoded.strip()) > 1:
                                all_text.append(decoded)
                        except:
                            pass
        except:
